UPDATE actions_config
SET config = jsonb_set(
    config,
    '{payment_method,config}',
    '{
        "newWoodlandMaxPercent": 20,
        "tiers": [
            {
                "lowerLimitHa": 0.5,
                "upperLimitHa": 51,
                "flatRateGbp": 1500,
                "ratePerUnitGbp": 0
            },
            {
                "lowerLimitHa": 50,
                "upperLimitHa": 100,
                "flatRateGbp": 1500,
                "ratePerUnitGbp": 30
            },
            {
                "lowerLimitHa": 100,
                "upperLimitHa": null,
                "flatRateGbp": 3000,
                "ratePerUnitGbp": 15
            }
        ]
    }'::jsonb
)
WHERE code = 'PA3'
    AND is_active = TRUE;
